Extensions.ExtractScript:
param(
    [xml] $Document
);

foreach( $file in $Document.unattend.Extensions.File ) {
    $path = [System.Environment]::ExpandEnvironmentVariables( $file.GetAttribute( 'path' ) );
    mkdir -Path( $path | Split-Path -Parent ) -ErrorAction 'SilentlyContinue';
    $encoding = switch( [System.IO.Path]::GetExtension( $path ) ) {
        { $_ -in '.ps1', '.xml' } { [System.Text.Encoding]::UTF8; }
        { $_ -in '.reg', '.vbs', '.js' } { [System.Text.UnicodeEncoding]::new( $false, $true ); }
        default { [System.Text.Encoding]::Default; }
    };
    $bytes = $encoding.GetPreamble() + $encoding.GetBytes( $file.InnerText.Trim() );
    [System.IO.File]::WriteAllBytes( $path, $bytes );
}

Extensions.File:
$selectors = @(
	'Microsoft.BingSearch';
	'Clipchamp.Clipchamp';
	'Microsoft.549981C3F5F10';
	'Microsoft.WindowsFeedbackHub';
	'Microsoft.Getstarted';
	'Microsoft.WindowsMaps';
	'Microsoft.BingNews';
	'Microsoft.Office.OneNote';
	'Microsoft.SkypeApp';
	'Microsoft.MicrosoftSolitaireCollection';
	'MicrosoftTeams';
	'MSTeams';
	'Microsoft.People';
	'Microsoft.MicrosoftOfficeHub';
	'Microsoft.Todos';
	'Microsoft.OutlookForWindows';
	'Microsoft.BingWeather';
	'Microsoft.Xbox.TCUI';
	'Microsoft.XboxApp';
	'Microsoft.XboxGameOverlay';
	'Microsoft.XboxGamingOverlay';
	'Microsoft.XboxSpeechToTextOverlay';
	'Microsoft.GamingApp';
);
$getCommand = {
  Get-AppxProvisionedPackage -Online;
};
$filterCommand = {
  $_.DisplayName -eq $selector;
};
$removeCommand = {
  [CmdletBinding()]
  param(
    [Parameter( Mandatory, ValueFromPipeline )]
    $InputObject
  );
  process {
    $InputObject | Remove-AppxProvisionedPackage -AllUsers -Online -ErrorAction 'Continue';
  }
};
$type = 'Package';
$logfile = 'C:\Windows\Setup\Scripts\RemovePackages.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

$selectors = @(
	'Browser.InternetExplorer';
);
$getCommand = {
  Get-WindowsCapability -Online | Where-Object -Property 'State' -NotIn -Value @(
    'NotPresent';
    'Removed';
  );
};
$filterCommand = {
  ($_.Name -split '~')[0] -eq $selector;
};
$removeCommand = {
  [CmdletBinding()]
  param(
    [Parameter( Mandatory, ValueFromPipeline )]
    $InputObject
  );
  process {
    $InputObject | Remove-WindowsCapability -Online -ErrorAction 'Continue';
  }
};
$type = 'Capability';
$logfile = 'C:\Windows\Setup\Scripts\RemoveCapabilities.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

$scripts = @(
	{
	#Bypass nro during oobe for offline installs
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\OOBE" /v BypassNRO /t REG_DWORD /d 1 /f;
	};
	{
	#Stop WindowsUpdate from force checking during setup
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Setup" /v DisableDynamicUpdate /t REG_DWORD /d 1 /f;
	};
	{
	#Allows win10 to upgrade to 11 without requirements
		reg.exe add "HKLM\SYSTEM\Setup\MoSetup" /v AllowUpgradesWithUnsupportedTPMOrCPU /t REG_DWORD /d 1 /f;
	};
	{
	#Prevents auto-install of Teams
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Communications" /v ConfigureChatAutoInstall /t REG_DWORD /d 0 /f;
	};
	{
		& 'C:\Windows\Setup\Scripts\RemovePackages.ps1';
	};
	{
		& 'C:\Windows\Setup\Scripts\RemoveCapabilities.ps1';
	};
	{
	#Do not enforce password change after x time
		net.exe accounts /maxpwage:UNLIMITED;
	};
	{
	#Enables long path in Documents for full Path display
		reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\FileSystem" /v LongPathsEnabled /t REG_DWORD /d 1 /f
	};
	{
	#logging system changes for troubleshooting
		auditpol.exe /set /subcategory:"{0CCE922B-69AE-11D9-BED3-505054503030}" /success:enable /failure:enable;
	};
	{
	#include cmd commands ran in audit logs for troubleshooting
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System\Audit" /v ProcessCreationIncludeCmdLine_Enabled /t REG_DWORD /d 1 /f;
	};
	{
	#reduces disk overhead, prevents windows from registering last time a file was looked at
		fsutil.exe behavior set disableLastAccess 1;
	};
	{
    # download updates directly from Microsoft and NEVER share update files with others.
    	reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\DeliveryOptimization" /v "DODownloadMode" /t REG_DWORD /d 0 /f;
	};
	{
    # Disables "Monthly Upload Limits" and background P2P activity.
    	reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\DeliveryOptimization\Config" /v "DODownloadMode" /t REG_DWORD /d 0 /f;
	};
	{
	#Warns theres an update to be downloaded. NEVER downloads automatically or installs, user must ask from windows update menu. opt for 1(ask both) or 3(auto down|ask install)
	#Prevents Windows from auto rebooting if anyone is logged in to the system
	#Sends minimal telemetry back to Microsoft
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate\AU" /v AUOptions /t REG_DWORD /d 1 /f;
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate\AU" /v NoAutoRebootWithLoggedOnUsers /t REG_DWORD /d 1 /f;
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\DataCollection" /v "AllowTelemetry" /t REG_DWORD /d 1 /f
	};
	{
	#Makes windows think youre never inactive
		Register-ScheduledTask -TaskName 'MoveActiveHours' -Xml $( Get-Content -LiteralPath 'C:\Windows\Setup\Scripts\MoveActiveHours.xml' -Raw );
	};
	{
	#Removes annoying news to prevent cluttering menus
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Dsh" /v AllowNewsAndInterests /t REG_DWORD /d 0 /f;
	};
	{
	#Stops windows from auto-installing apps like TikTok,CandyCrush,Spotify, etc...
	#Cuts off usage data telemetry, used to serve you ads
		reg.exe add "HKLM\Software\Policies\Microsoft\Windows\CloudContent" /v "DisableWindowsConsumerFeatures" /t REG_DWORD /d 1 /f;
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\CloudContent" /v "DisableTailoredExperiencesWithDiagnosticData" /t REG_DWORD /d 1 /f
	};
	{
	#Prevents win11 from force criptographing your drive via Bitlocker, can still enable on settings later
		reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\BitLocker" /v "PreventDeviceEncryption" /t REG_DWORD /d 1 /f;
	};
	{
	#Removes Edge first experience annoying pop-ups, quicker to install a better browser lol
	#Stops edge from squatting on your RAM
		reg.exe add "HKLM\Software\Policies\Microsoft\Edge" /v HideFirstRunExperience /t REG_DWORD /d 1 /f;
		reg.exe add "HKLM\Software\Policies\Microsoft\Edge\Recommended" /v BackgroundModeEnabled /t REG_DWORD /d 0 /f;
		reg.exe add "HKLM\Software\Policies\Microsoft\Edge\Recommended" /v StartupBoostEnabled /t REG_DWORD /d 0 /f;
	};
	{
	#Stops MicrosoftStore from auto updating or downloading anything you didnt ask for. will still warn you about them 
	  reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\WindowsStore" /v AutoDownload /t REG_DWORD /d 2 /f;
	};
	{
		& 'C:\Windows\Setup\Scripts\SetStartPins.ps1';
	};
	{
	#Prevents windows from auto booting into your user session logged in after updates
		reg.exe add "HKLM\Software\Microsoft\Windows\CurrentVersion\Policies\System" /v "DisableAutomaticRestartSignOn" /t REG_DWORD /d 1 /f;
	};
	{
	#Kills windows PhoneHome for new ads
	#Kills Network Pushed installations
		Get-ScheduledTask -TaskPath "\Microsoft\Windows\ContentDeliveryManager\" | Disable-ScheduledTask -ErrorAction SilentlyContinue
    	Get-ScheduledTask -TaskPath "\Microsoft\Windows\PushToInstall\" | Disable-ScheduledTask -ErrorAction SilentlyContinue
    };
	{
	#Creates an AppLocker service instance that starts with your PC. Wont stop you from running anything but will log if any unsigned exe is ran from user folders.
		Get-Service -Name 'AppIDSvc' | Set-Service -StartupType 'Automatic';
		Get-Service -Name 'AppIDSvc' | Start-Service;
		Set-AppLockerPolicy -XmlPolicy 'C:\Windows\Setup\Scripts\AppLockerPolicy.xml';
	};
	{
	# Stops Windows from collecting user activities (Timeline)
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\System" /v "EnableActivityFeed" /t REG_DWORD /d 0 /f;
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\System" /v "PublishUserActivities" /t REG_DWORD /d 0 /f;
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows\System" /v "UploadUserActivities" /t REG_DWORD /d 0 /f;
	};
	{
	# Disable the ad telemetry service, Goodbye windows compatibility telemetry!
	# No bullshit push notifications
	# HAHAHAHA REMOTELY EDIT YOUR REGISTRY???? , not anymore
		Get-Service -Name 'DiagTrack' | Set-Service -StartupType 'Disabled';
		Get-Service -Name 'dmwappushservice' -ErrorAction SilentlyContinue | Set-Service -StartupType 'Disabled';
		Get-Service -Name 'RemoteRegistry' -ErrorAction SilentlyContinue | Set-Service -StartupType 'Disabled';
	};
	{
	#Just in case.... some security tweaks, disabling legacy protocols and dangerous functions rarely used:
	# SMB1 = Eternal Blue(just in case they're lying  no more multicast(gaming?)
	# NETBIOS2, legacy attack surface. just use DNS or mDNS
	# Remote Assist = Scam remote acess
	# AutoRun = no pendrive autorun software will work(only run apps from external drives if you ask)
	# No more LLMNS multicast
	# No more WifiSense, i mean wtf were they thinking???
	# No more making your PC a labrat for Microsoft untested software

		Set-SmbServerConfiguration -EnableSMB1Protocol $false -Force; 
		Disable-WindowsOptionalFeature -Online -FeatureName SMB1Protocol -NoRestart; 
		$adapters = Get-WmiObject Win32_NetworkAdapterConfiguration; $adapters | ForEach-Object { $_.SetTcpipNetbios(2) };
		reg.exe add "HKLM\SYSTEM\CurrentControlSet\Control\Remote Assistance" /v fAllowToGetHelp /t REG_DWORD /d 0 /f;
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer" /v "NoDriveTypeAutoRun" /t REG_DWORD /d 255 /f
		reg.exe add "HKLM\SOFTWARE\Policies\Microsoft\Windows NT\DNSClient" /v "EnableMulticast" /t REG_DWORD /d 0 /f
		reg.exe add "HKLM\SOFTWARE\Microsoft\WcmSvc\wifinetworkmanager\config" /v AutoConnectAllowedOEM /t REG_DWORD /d 0 /f;
		reg.exe add "HKLM\SOFTWARE\Microsoft\PolicyManager\current\device\System" /v "AllowExperimentation" /t REG_DWORD /d 0 /f;

	};
	{
	# Disables hidden administrative shares (C$, etc.), prevents lateral movement techniques
		reg.exe add "HKLM\SYSTEM\CurrentControlSet\Services\LanmanServer\Parameters" /v "AutoShareWks" /t REG_DWORD /d 0 /f;
	};
	{
	#ensure firewall is active
		Set-NetFirewallProfile -Profile Domain,Public,Private -Enabled True;
	};
);

& {
  [float] $complete = 0;
  [float] $increment = 100 / $scripts.Count;
  foreach( $script in $scripts ) {
    Write-Progress -Id 0 -Activity 'Running scripts to customize your Windows installation. Do not close this window.' -PercentComplete $complete;
    '*** Will now execute command «{0}».' -f $(
      $str = $script.ToString().Trim() -replace '\s+', ' ';
      $max = 100;
      if( $str.Length -le $max ) {
        $str;
      } else {
        $str.Substring( 0, $max - 1 ) + '…';
      }
    );
    $start = [datetime]::Now;
    & $script;
    '*** Finished executing command after {0:0} ms.' -f [datetime]::Now.Subtract( $start ).TotalMilliseconds;
    "`r`n" * 3;
    $complete += $increment;
  }
} *>&1 | Out-String -Width 1KB -Stream >> "C:\Windows\Setup\Scripts\Specialize.log";

